// TestScore_UnsupportedLanguage_ReturnsNA verifies that Score returns nil
// (no fabricated dimension scores) for languages not registered in the
// analysis package (TierGeneric), e.g. Swift.
func TestScore_UnsupportedLanguage_ReturnsNA(t *testing.T) {
	ev := []domain.Evidence{
		evidence.LintResult{Tool: "swiftlint", ErrorCount: 2}.ToEvidence(),
		evidence.TestResult{Tool: "xctest", TotalCount: 10, PassedCount: 8, Coverage: 0.7}.ToEvidence(),
		evidence.CodeMetrics{TotalLines: 200, CodeLines: 150, Complexity: 3}.ToEvidence(),
	}

	scores := engine.Score(ev, policy.EvaluationResult{Passed: true}, "swift")

	// Unsupported language must produce nil DimensionScores — no fabricated
	// dimensions should appear.
	if scores != nil {
		t.Errorf("unsupported language should return nil scores, got %v with %d entries", scores, len(scores))
	}

	// Verify weighted average on nil is zero (no phantom scores).
	avg := scores.WeightedAverage(nil)
	if avg != 0 {
		t.Errorf("nil scores weighted average = %f, want 0", avg)
	}
}

